SELECT COUNT(*) 
FROM event_segments 
WHERE created_by = 'user2';

SELECT DISTINCT category
FROM event_segments
ORDER BY category ASC;

SELECT category, COUNT(*) AS segment_count
FROM event_segments
GROUP BY category;

SELECT DENSE_RANK() OVER (PARTITION BY event_id ORDER BY start_time) AS event_segment_rank
FROM event_segments
ORDER BY event_id, start_time;

SELECT segment_id, COUNT(descriptor_id) AS total_descriptors
FROM event_descriptors
GROUP BY segment_id;
